#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAXN 50

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return *x - *y;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int count = 1;
        int found = 0;
        int arr[1000][50];
        memcpy(arr, A, N * sizeof(int));
        while (1) {
            found = 0;
            for (int i = 0; i < count; i++) {
                for (int j = 0; j < N - 1; j++) {
                    if (arr[i * (N + 1) + j] > 0 && arr[i * (N + 1) + j + 1] > 0) {
                        int B[N + 1];
                        memcpy(B, arr + i * (N + 1), (N + 1) * sizeof(int));
                        B[j]--;
                        B[j + 1]--;
                        if (j + 2 < N) {
                            B[j + 2]++;
                        } else {
                            B[N] = 1;
                        }
                        qsort(B, N + 1, sizeof(int), compare);
                        int k;
                        for (k = 0; k < count; k++) {
                            if (memcmp(B, arr + k * (N + 1), (N + 1) * sizeof(int)) == 0) {
                                break;
                            }
                        }
                        if (k == count) {
                            memcpy(arr + count * (N + 1), B, (N + 1) * sizeof(int));
                            count++;
                            found = 1;
                        }
                    }
                }
            }
            if (!found) {
                break;
            }
        }
        printf("%d\n", count % MOD);
    }
    return 0;
}

